using Microsoft.EntityFrameworkCore;

class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(b =>
        {
            b.ToContainer("Products");

            // Breaking change: discriminator property renamed from "Discriminator" to "$type".
            // Preserve old name so existing 500K documents and direct SQL queries still work.
            b.HasDiscriminator<string>("Discriminator");

            // Breaking change: id no longer includes discriminator prefix.
            // Preserve "Product|{key}" format so lookups against existing documents succeed.
            b.HasDiscriminatorInJsonId();

            // Breaking change: key property is now mapped directly to JSON id.
            // Preserve the shadow id so existing documents that store Id as a separate
            // JSON property continue to round-trip correctly.
            b.HasShadowId();

            // Breaking change: HasIndex now throws instead of being silently ignored.
            // Removed — Cosmos DB indexes all properties by default.
            // Configure custom indexing policy in the Azure Portal if needed.
        });
    }
}

class Product { public int Id { get; set; } public string Sku { get; set; } }

